code_changes.content:
[
  {
    "file": "src/Components/Web/src/Forms/DisplayName.cs",
    "line": 27,
    "severity": "high",
    "description": "The 'For' parameter is declared as nullable (Expression<Func<TValue>>?) but is marked as [EditorRequired], which indicates it must be provided. This is a type contract contradiction. Since ExpressionMemberAccessor.GetDisplayName(For) will throw ArgumentNullException if For is null, the property should not be nullable. This makes the type signature misleading and can cause runtime exceptions.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/DisplayName.cs
+++ b/src/Components/Web/src/Forms/DisplayName.cs
@@ -24,7 +24,7 @@ public class DisplayName<TValue> : IComponent
     /// <summary>
     /// Specifies the field for which the display name should be shown.
     /// </summary>
     [Parameter, EditorRequired]
-    public Expression<Func<TValue>>? For { get; set; }
+    public Expression<Func<TValue>> For { get; set; }
     /// <inheritdoc />
     void IComponent.Attach(RenderHandle renderHandle)
"
  },
  {
    "file": "src/Components/Web/src/Forms/DisplayName.cs",
    "line": 39,
    "severity": "medium",
    "description": "The SetParametersAsync method always calls _renderHandle.Render(BuildRenderTree) regardless of whether the display name actually changed. This is an unnecessary re-render that violates ASP.NET Core component rendering best practices. The component should only render when the output changes. The unused field '_previousFieldAccessor' indicates this was an oversight.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/DisplayName.cs
+++ b/src/Components/Web/src/Forms/DisplayName.cs
@@ -37,12 +37,13 @@ public class DisplayName<TValue> : IComponent
     Task IComponent.SetParametersAsync(ParameterView parameters)
     {
         parameters.SetParameterProperties(this);

         var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
-        _displayName = newDisplayName;
-        _renderHandle.Render(BuildRenderTree);
+        if (_displayName != newDisplayName)
+        {
+            _displayName = newDisplayName;
+            _renderHandle.Render(BuildRenderTree);
+        }

         return Task.CompletedTask;
     }
"
  },
  {
    "file": "src/Components/Web/src/Forms/ExpressionMemberAccessor.cs",
    "line": 88,
    "severity": "critical",
    "description": "The ClearCache() method only clears _memberInfoCache but not _displayNameCache. When hot reload applies metadata updates (e.g., DisplayName or DisplayNameAttribute attributes change), the display name cache is not cleared, causing stale display names to be returned. This breaks the hot reload feature. Both caches must be cleared together.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -86,5 +86,6 @@ internal static class ExpressionMemberAccessor
     private static void ClearCache()
     {
         _memberInfoCache.Clear();
+        _displayNameCache.Clear();
     }
 }
"
  }
]

